1	//! Slice-2.3 userland bootstrap: minimal TTBR0 setup + EL0 stub task.
2	//!
3	//! Builds a single 4-level page-table walk in static `.bss` storage that
4	//! maps two pages:
5	//!   - `USER_CODE_VA` → a kernel-owned page filled with the EL0 stub
6	//!     instructions (`_user_stub_start..._user_stub_end`). RO + EL0 X.
7	//!   - `USER_STACK_VA` → a kernel-owned page used as the stub's EL0 stack.
8	//!     RW + EL0, no execute.
9	//!
10	//! Populates the first free user slot in the process table (ProcNr 11 — the
11	//! slot immediately after the boot servers, currently empty) with the EL0
12	//! entry state, and returns it for `proc::sched::switch_to_user` to consume.
13	//!
14	//! Phase 3's VM server replaces all of this with proper per-process address
15	//! spaces; slice 2.4 reuses the page-table arena to add a second EL0 stub
16	//! task that exercises timer-driven preemption.
17	
18	use core::cell::UnsafeCell;
19	use core::sync::atomic::Ordering;
20	
21	use minix4_kernel_shared::ProcNr;
22	use minix4_kernel_shared::com::boot_endpoint;
23	
24	use crate::arch::aarch64::limine::kernel_va_to_pa;
25	use crate::arch::aarch64::mmu::{
26	    self, ATTR_IDX_NORMAL, PAGE_SIZE, PTE_AF, PTE_AP_RO_EL0, PTE_AP_RW_EL0, PTE_PXN,
27	    PTE_SH_INNER, PTE_UXN, PageTable, pte_attr_idx,
28	};
29	use crate::proc::Proc;
30	use crate::proc::table::proc_slot_mut;
31	
32	// ----- EL0 virtual addresses ------------------------------------------------
33	
34	/// Virtual address at which the EL0 stub's code page is mapped.
35	pub const USER_CODE_VA: u64 = 0x0040_0000; // 4 MiB
36	/// Virtual address at which the EL0 stub's stack page is mapped.
37	pub const USER_STACK_VA: u64 = 0x0080_0000; // 8 MiB
38	
39	/// First proc-table slot beyond the boot image (`NR_TASKS + NR_BOOT_PROCS =
40	/// 5 + 11 = 16`, which corresponds to `ProcNr(11)`). Slice 2.6 will replace
41	/// this ad-hoc occupant with a properly-loaded INIT.
42	const STUB_PROC_NR: ProcNr = ProcNr::new(11);
43	
44	// ----- Static storage ------------------------------------------------------
45	
46	/// 4 KiB-aligned raw byte page, used for the EL0 stub's code and stack.
47	#[repr(C, align(4096))]
48	struct UserPage(UnsafeCell<[u8; PAGE_SIZE]>);
49	// SAFETY: single-threaded boot context; no concurrent access. Same invariant
50	// documented on `ProcStorage` / `PrivStorage` in `proc::table`.
51	unsafe impl Sync for UserPage {}
52	
53	impl UserPage {
54	    const EMPTY: Self = Self(UnsafeCell::new([0; PAGE_SIZE]));
55	}
56	
57	#[repr(transparent)]
58	struct PtSlot(UnsafeCell<PageTable>);
59	// SAFETY: single-threaded boot; mutation is confined to `userland_bootstrap`.
60	unsafe impl Sync for PtSlot {}
61	
62	static L0_TABLE: PtSlot = PtSlot(UnsafeCell::new(PageTable::EMPTY));
63	static L1_TABLE: PtSlot = PtSlot(UnsafeCell::new(PageTable::EMPTY));
64	static L2_TABLE: PtSlot = PtSlot(UnsafeCell::new(PageTable::EMPTY));
65	static L3_CODE_TABLE: PtSlot = PtSlot(UnsafeCell::new(PageTable::EMPTY));
66	static L3_STACK_TABLE: PtSlot = PtSlot(UnsafeCell::new(PageTable::EMPTY));
67	
68	static USER_CODE_PAGE: UserPage = UserPage::EMPTY;
69	static USER_STACK_PAGE: UserPage = UserPage::EMPTY;
70	
71	// ----- EL0 stub blob (linked into the kernel image by `user_stub.S`) -------
72	
73	unsafe extern "C" {
74	    static _user_stub_start: u8;
75	    static _user_stub_end: u8;
76	}
77	
78	// ----- Bootstrap ----------------------------------------------------------
79	
80	/// Wire up TTBR0 mappings, copy the EL0 stub into its user page, populate
81	/// the stub's process slot, and return it.
82	///
83	/// SAFETY: must be called exactly once from `kmain` before any EL0 code
84	/// runs. Single-threaded boot context; no other reference into the static
85	/// page-table arena, user pages, or `PROC_TABLE[STUB_PROC_NR]` may exist
86	/// concurrently.
87	pub unsafe fn userland_bootstrap() -> &'static mut Proc {
88	    // 1. Verify Limine left MAIR_EL1's index 0 as Normal WB. We rely on it
89	    //    for both user pages; rewriting MAIR would silently retype any
90	    //    kernel page that uses an index we change.
91	    mmu::assert_mair_normal_wb();
92	
93	    // 2. Resolve physical addresses for our static storage. The page tables
94	    //    and the user code/stack pages all live in the kernel image (`.bss`
95	    //    section, mapped via TTBR1), so we go through Limine's kernel-
96	    //    address response rather than HHDM.
97	    let l0_pa = kernel_pa_of(L0_TABLE.0.get() as u64);
98	    let l1_pa = kernel_pa_of(L1_TABLE.0.get() as u64);
99	    let l2_pa = kernel_pa_of(L2_TABLE.0.get() as u64);
100	    let l3_code_pa = kernel_pa_of(L3_CODE_TABLE.0.get() as u64);
101	    let l3_stack_pa = kernel_pa_of(L3_STACK_TABLE.0.get() as u64);
102	    let code_page_pa = kernel_pa_of(USER_CODE_PAGE.0.get() as u64);
103	    let stack_page_pa = kernel_pa_of(USER_STACK_PAGE.0.get() as u64);
104	
105	    // 3. Build the two user mappings. The arena holds 5 tables total: L0,
106	    //    L1, L2 (shared because both VAs fall in the same 1 GiB L1 entry),
107	    //    and one L3 each (the code/stack VAs straddle different 2 MiB L2
108	    //    slots, so they need separate L3 tables).
109	    let code_attrs = PTE_AF | PTE_SH_INNER | PTE_AP_RO_EL0 | PTE_PXN | pte_attr_idx(ATTR_IDX_NORMAL);
110	    let stack_attrs = PTE_AF
111	        | PTE_SH_INNER
112	        | PTE_AP_RW_EL0
113	        | PTE_PXN
114	        | PTE_UXN
115	        | pte_attr_idx(ATTR_IDX_NORMAL);
116	
117	    // SAFETY: single-threaded boot; no other references into the table
118	    // storage exist. PAs were resolved above.
119	    unsafe {
120	        let l0 = &mut *L0_TABLE.0.get();
121	        let l1 = &mut *L1_TABLE.0.get();
122	        let l2 = &mut *L2_TABLE.0.get();
123	        let l3_code = &mut *L3_CODE_TABLE.0.get();
124	        let l3_stack = &mut *L3_STACK_TABLE.0.get();
125	
126	        mmu::map_4k(
127	            l0, l1, l2, l3_code,
128	            l1_pa, l2_pa, l3_code_pa,
129	            USER_CODE_VA, code_page_pa, code_attrs,
130	        );
131	        mmu::map_4k(
132	            l0, l1, l2, l3_stack,
133	            l1_pa, l2_pa, l3_stack_pa,
134	            USER_STACK_VA, stack_page_pa, stack_attrs,
135	        );
136	    }
137	
138	    // 4. Copy the EL0 stub into its code page (via the kernel VA), then
139	    //    clean the data side to PoU and invalidate the i-cache so the
140	    //    upcoming EL0 fetch sees the new bytes.
141	    // SAFETY: `_user_stub_*` are rodata symbols inside the kernel image;
142	    // start ≤ end is enforced by the linker output of user_stub.S.
143	    let stub_len = unsafe {
144	        (&_user_stub_end as *const u8).offset_from(&_user_stub_start as *const u8) as usize
145	    };
146	    assert!(stub_len > 0 && stub_len <= PAGE_SIZE);
147	    // SAFETY: USER_CODE_PAGE is a 4 KiB-aligned BSS page; we hold the only
148	    // mutable reference (single-threaded boot).
149	    unsafe {
150	        let dst = USER_CODE_PAGE.0.get() as *mut u8;
151	        core::ptr::copy_nonoverlapping(&_user_stub_start as *const u8, dst, stub_len);
152	        mmu::flush_icache_range(USER_CODE_PAGE.0.get() as u64, stub_len);
153	    }
154	
155	    // 5. Install TTBR0 with our L0 root. After this, USER_CODE_VA and
156	    //    USER_STACK_VA resolve to the pages we just prepared.
157	    // SAFETY: DAIF is masked from boot (Limine hands us a state with all
158	    //   four DAIF bits set). The L0 root we just built is valid.
159	    unsafe { mmu::activate_user_ttbr0(l0_pa) };
160	
161	    // 6. Populate the stub's proc slot with its EL0 entry state.
162	    // SAFETY: single-threaded boot; nobody else holds a reference into the
163	    // stub slot. Slice 2.2's `proc::init` left ProcNr 11 in the
164	    // RTS_SLOT_FREE state.
165	    let p = unsafe { proc_slot_mut(STUB_PROC_NR) }
166	        .expect("STUB_PROC_NR within proc table");
167	    populate_stub_slot(p);
168	    p
169	}
170	
171	fn populate_stub_slot(p: &mut Proc) {
172	    // Name "el0stub" + NUL fill.
173	    p.name = *b"el0stub\0\0\0\0\0\0\0\0\0";
174	    p.nr = STUB_PROC_NR;
175	    p.endpoint = boot_endpoint(STUB_PROC_NR);
176	    p.priv_id = None; // No Priv slot — trap-mask enforcement is slice 2.5.
177	    p.priority = crate::proc::table::SRV_Q;
178	    p.quantum_ms = 0;
179	    p.quantum_left = 0;
180	
181	    // EL0 entry state.
182	    p.regs.elr_el1 = USER_CODE_VA;
183	    p.regs.sp_el0 = USER_STACK_VA + PAGE_SIZE as u64;
184	    // SPSR_EL1 = 0x3C0:
185	    //   bits 9:6  (DAIF) = 1111 — keep interrupts masked until slice 2.4.
186	    //   bit  4    (M[4]) = 0    — AArch64.
187	    //   bits 3:0  (M[3:0]) = 0  — EL0t (SP = SP_EL0).
188	    p.regs.spsr_el1 = 0x3C0;
189	
190	    // Mark runnable — RTS_SLOT_FREE was set by Proc::EMPTY; clearing all
191	    // RTS bits makes the slot a live, ready process.
192	    p.rts_flags.store(0, Ordering::Relaxed);
193	}
194	
195	/// Translate a kernel-image VA to PA via Limine's kernel-address response,
196	/// panicking with a usable message if Limine didn't fill that response in.
197	fn kernel_pa_of(va: u64) -> u64 {
198	    kernel_va_to_pa(va).expect(
199	        "Limine did not populate the kernel-address response — bootloader too old?",
200	    )
201	}
202

