113	/// physical addresses must be reachable via [`super::limine::kernel_va_to_pa`].
114	pub unsafe fn map_4k(
115	    l0: &mut PageTable,
116	    l1: &mut PageTable,
117	    l2: &mut PageTable,
118	    l3: &mut PageTable,
119	    l1_pa: u64,
120	    l2_pa: u64,
121	    l3_pa: u64,
122	    va: u64,
123	    pa: u64,
124	    attrs: u64,
125	) {
126	    l0.set(pte_index(va, 0), make_table_desc(l1_pa));
127	    l1.set(pte_index(va, 1), make_table_desc(l2_pa));
128	    l2.set(pte_index(va, 2), make_table_desc(l3_pa));
129	    l3.set(pte_index(va, 3), make_page_desc(pa, attrs));
130	}
131	
132	// ----- TTBR0 / TCR / MAIR ---------------------------------------------------
133	
134	/// Verify Limine programmed AttrIdx 0 = Normal WB. We rely on this index
135	/// throughout slice 2.3.
136	pub fn assert_mair_normal_wb() {
137	    let mair: u64;
138	    // SAFETY: MAIR_EL1 is readable at EL1; no side effects.
139	    unsafe {
140	        asm!("mrs {0}, mair_el1", out(reg) mair, options(nomem, nostack, preserves_flags));
141	    }
142	    assert!(
143	        (mair & 0xFF) as u8 == MAIR_NORMAL_BYTE,
144	        "MAIR_EL1[7:0] = {:#04x}, expected Normal WB = {:#04x}",
145	        (mair & 0xFF) as u8,
146	        MAIR_NORMAL_BYTE,
147	    );
148	}
149	
150	/// Install `root_pa` as TTBR0_EL1 and ensure TTBR0 walks are enabled.
151	///
152	/// Limine has already programmed TCR_EL1 with T0SZ=16, TG0=4 KiB,
153	/// IRGN0=ORGN0=WBWA, SH0=Inner (verified by the diagnostic print in kmain),
154	/// so we only need to clear EPD0 if set. We deliberately read-modify-write
155	/// just bit 7 — touching any other TCR field risks perturbing TTBR1, which
156	/// Limine owns and whose translations the kernel is actively using.
157	///
158	/// SAFETY: must be called with interrupts masked. `root_pa` must point at a
159	/// valid L0 page table.
160	pub unsafe fn activate_user_ttbr0(root_pa: u64) {
161	    const TCR_EPD0: u64 = 1 << 7;
162	
163	    // SAFETY: TTBR0_EL1, TCR_EL1, and TLB-maintenance ops are EL1-only and
164	    // touch no normal memory. Bit 7 (EPD0) is the only TCR field we
165	    // perturb; the rest stays as Limine left it.
166	    unsafe {
167	        let tcr: u64;
168	        asm!("mrs {0}, tcr_el1", out(reg) tcr, options(nomem, nostack, preserves_flags));
169	        let new_tcr = tcr & !TCR_EPD0;
170	
171	        asm!(
172	            "msr ttbr0_el1, {root}",
173	            "msr tcr_el1, {tcr}",
174	            "isb",
175	            "tlbi vmalle1",
176	            "dsb ish",
177	            "isb",
178	            root = in(reg) root_pa,
179	            tcr = in(reg) new_tcr,
180	            options(nomem, nostack, preserves_flags),
181	        );
182	    }
183	}
184	
185	/// Make instruction memory coherent with a recent data write at `va..va+len`.
186	///
187	/// AArch64 caches are PIPT for data but VIPT-flavored for instructions; after
188	/// writing into a code page we must clean the data side to PoU, then
189	/// invalidate the i-cache. Sequence is straight out of the ARM ARM §B2.4
190	/// example.
191	///
192	/// SAFETY: `va..va+len` must be a valid mapped range readable at EL1.
193	pub unsafe fn flush_icache_range(va: u64, len: usize) {
194	    // Cache-line size: read CTR_EL0.DminLine to get the data-side line size
195	    // in words (4 B). 0 means "default", but we always set it conservatively
196	    // to 64 bytes on QEMU virt (cortex-a72 default).
197	    const LINE_BYTES: u64 = 64;
198	
199	    let mut p = va & !(LINE_BYTES - 1);
200	    let end = va + len as u64;
201	    while p < end {
202	        // SAFETY: `dc cvau` / `ic ivau` are EL0-permissive cache ops on a
203	        // VA already known to be mapped; no memory access semantically.
204	        unsafe {
205	            asm!("dc cvau, {0}", in(reg) p, options(nostack, preserves_flags));
206	        }
207	        p += LINE_BYTES;
208	    }
209	    // SAFETY: barrier + i-cache invalidation; no memory access.
210	    unsafe {
211	        asm!(
212	            "dsb ish",
213	            "ic iallu",
214	            "dsb ish",
215	            "isb",
216	            options(nomem, nostack, preserves_flags),
217	        );
218	    }
219	}
