/// Verify Limine programmed TCR_EL1's TTBR0-side fields the way we expect:
/// 48-bit VA (T0SZ=16), 4 KiB granule, Normal WB cacheable, Inner Shareable.
/// `activate_user_ttbr0` relies on these without rewriting them; if a future
/// Limine ever ships a different config we want to panic here rather than
/// translation-fault on the first EL0 fetch.
pub fn assert_tcr_el1_ttbr0_ready() {
    let tcr: u64;
    // SAFETY: TCR_EL1 is readable at EL1; no side effects.
    unsafe {
        asm!("mrs {0}, tcr_el1", out(reg) tcr, options(nomem, nostack, preserves_flags));
    }

    let t0sz = tcr & 0x3F;
    let irgn0 = (tcr >> 8) & 0x3;
    let orgn0 = (tcr >> 10) & 0x3;
    let sh0 = (tcr >> 12) & 0x3;
    let tg0 = (tcr >> 14) & 0x3;

    assert!(
        t0sz == 16 && irgn0 == 0b01 && orgn0 == 0b01 && sh0 == 0b11 && tg0 == 0b00,
        "TCR_EL1 = {tcr:#018x} (T0SZ={t0sz} IRGN0={irgn0} ORGN0={orgn0} SH0={sh0} TG0={tg0}), \
         expected T0SZ=16 IRGN0=1 ORGN0=1 SH0=3 TG0=0",
    );
}

