        asm!(
            "msr ttbr0_el1, {root}",
            "msr tcr_el1, {tcr}",
            "isb",
            "tlbi vmalle1",
            "dsb ish",
            "isb",
            root = in(reg) root_pa,
            tcr = in(reg) new_tcr,
            options(nomem, nostack, preserves_flags),
        );
    }
